import{_ as i,o as t,c as s,ao as a}from"./chunks/framework.C2uOknPB.js";const u=JSON.parse('{"title":"Building","description":"","frontmatter":{},"headers":[],"relativePath":"guide/building.md","filePath":"guide/building.md","lastUpdated":null}'),l={name:"guide/building.md"};function n(o,e,d,h,p,r){return t(),s("div",null,[...e[0]||(e[0]=[a(`<h1 id="Building" tabindex="-1">Building <a class="header-anchor" href="#Building" aria-label="Permalink to &quot;Building {#Building}&quot;">​</a></h1><p>ParselTongue offers two build entry points.</p><h2 id="build_wheel-—-a-self-contained,-pip-installable-wheel" tabindex="-1"><code>build_wheel</code> — a self-contained, pip-installable wheel <a class="header-anchor" href="#build_wheel-—-a-self-contained,-pip-installable-wheel" aria-label="Permalink to &quot;\`build_wheel\` — a self-contained, pip-installable wheel {#build_wheel-—-a-self-contained,-pip-installable-wheel}&quot;">​</a></h2><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">build_wheel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mymod.jl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; version </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;0.2.0&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, outdir </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;dist&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Produces <code>dist/mymod-0.2.0-&lt;pytag&gt;.whl</code> that bundles the Julia runtime. Install it with <code>pip</code> on any compatible machine — <strong>no Julia required</strong>. This is what you ship.</p><p>The wheel layout:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mymod/__init__.py                     re-exports the compiled extension</span></span>
<span class="line"><span>mymod/_mymod.&lt;EXT_SUFFIX&gt;             the extension (PyInit__mymod)</span></span>
<span class="line"><span>mymod/julia/lib/libjulia.so.1.x       Julia runtime, original relative layout</span></span>
<span class="line"><span>mymod/julia/lib/julia/…               preserved so the libs resolve each other</span></span>
<span class="line"><span>mymod-&lt;ver&gt;.dist-info/{METADATA,WHEEL,RECORD}</span></span></code></pre></div><h2 id="build_extension-—-just-the-extension-.so" tabindex="-1"><code>build_extension</code> — just the extension <code>.so</code> <a class="header-anchor" href="#build_extension-—-just-the-extension-.so" aria-label="Permalink to &quot;\`build_extension\` — just the extension \`.so\` {#build_extension-—-just-the-extension-.so}&quot;">​</a></h2><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">build_extension</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mymod.jl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; outdir </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;build&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Produces only <code>build/mymod.&lt;EXT_SUFFIX&gt;</code> and does <strong>not</strong> bundle libjulia — the surrounding environment must provide it (its rpath points at the Julia that built it). Useful for local iteration and testing.</p><h2 id="Options" tabindex="-1">Options <a class="header-anchor" href="#Options" aria-label="Permalink to &quot;Options {#Options}&quot;">​</a></h2><p>Both functions accept:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Keyword</th><th style="text-align:right;">Default</th><th style="text-align:right;">Meaning</th></tr></thead><tbody><tr><td style="text-align:right;"><code>mod_name</code></td><td style="text-align:right;">from <code>@pymodule</code>, else the file&#39;s base name</td><td style="text-align:right;">Python module name</td></tr><tr><td style="text-align:right;"><code>outdir</code></td><td style="text-align:right;">next to the source file</td><td style="text-align:right;">output directory</td></tr><tr><td style="text-align:right;"><code>trim</code></td><td style="text-align:right;"><code>:safe</code></td><td style="text-align:right;"><code>:safe</code> errors on dynamic dispatch; <code>:unsafe</code> / <code>:unsafe_warn</code> relax it</td></tr><tr><td style="text-align:right;"><code>python</code></td><td style="text-align:right;"><code>&quot;python3&quot;</code></td><td style="text-align:right;">the Python interpreter to target</td></tr><tr><td style="text-align:right;"><code>verbose</code></td><td style="text-align:right;"><code>false</code></td><td style="text-align:right;">print the juliac and link commands</td></tr></tbody></table><p><code>build_wheel</code> additionally takes <code>version</code> (default <code>&quot;0.1.0&quot;</code>), <code>runtime</code> (<code>:bundled</code> / <code>:shared</code> / <code>:system</code>), <code>slim</code>, <code>manylinux</code>, <code>abi3</code>, and <code>emit_pyproject</code>.</p><h3 id="emit_pyproject-—-a-publishable-project-layout" tabindex="-1"><code>emit_pyproject</code> — a publishable project layout <a class="header-anchor" href="#emit_pyproject-—-a-publishable-project-layout" aria-label="Permalink to &quot;\`emit_pyproject\` — a publishable project layout {#emit_pyproject-—-a-publishable-project-layout}&quot;">​</a></h3><p>Pass <code>emit_pyproject=true</code> to write a minimal PEP 621 <code>pyproject.toml</code> next to the wheel, turning the output directory into a project layout ready for <code>twine upload</code> / PyPI:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">build_wheel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mymod.jl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; version</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1.0.0&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, outdir</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dist&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, emit_pyproject</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># dist/mymod-1.0.0-…-linux_x86_64.whl</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># dist/pyproject.toml   ← name, version, requires-python, numpy extra</span></span></code></pre></div><p><code>requires-python</code> is <code>&gt;=3.11</code> for <code>abi3=true</code> wheels (which run on any CPython ≥ 3.11), otherwise the build interpreter&#39;s version. A <code>runtime=:shared</code> build adds the <code>parseltongue-runtime</code> dependency. The wheel itself is still produced by juliac — the <code>pyproject.toml</code> documents project metadata for publishing tools. On the CLI: <code>pt wheel mymod.jl --emit-pyproject</code>.</p><h3 id="Multi-module-wheels" tabindex="-1">Multi-module wheels <a class="header-anchor" href="#Multi-module-wheels" aria-label="Permalink to &quot;Multi-module wheels {#Multi-module-wheels}&quot;">​</a></h3><p>To ship several modules that import together in one Python process, aggregate their source files into a single extension with <a href="/ParselTongue.jl/dev/reference/api#Building"><code>build_multi_wheel</code></a>:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># geo.jl:  @pymodule geo begin … end</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># num.jl:  @pymodule num begin … end</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">build_multi_wheel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">([</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;geo.jl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;num.jl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mathpkg&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; outdir</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dist&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># python -c &quot;import mathpkg; mathpkg.geo.area(3,4); mathpkg.num.gcd_(12,18)&quot;</span></span></code></pre></div><p>Each file&#39;s bare <code>@pymodule &lt;name&gt;</code> becomes a submodule <code>mathpkg.&lt;name&gt;</code>. They share <strong>one</strong> Julia runtime image (one <code>jl_init</code>), which is required — two separately compiled extensions cannot coexist in a process (see <a href="/ParselTongue.jl/dev/guide/limitations#One-extension-per-Python-process">Limitations</a>). Function names must be unique across the files (they share one C method table). All the <code>runtime</code>, <code>slim</code>, <code>abi3</code>, and <code>emit_pyproject</code> options work as in <code>build_wheel</code>.</p><h3 id="Trim-modes" tabindex="-1">Trim modes <a class="header-anchor" href="#Trim-modes" aria-label="Permalink to &quot;Trim modes {#Trim-modes}&quot;">​</a></h3><p><code>--trim=safe</code> (the default) makes juliac <strong>error at build time</strong> if an exported code path needs dynamic dispatch — the failure is reported as a Julia stack-frame, before any wheel is produced. If you hit one, the usual fix is to make the offending function type-stable. As an escape hatch:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">build_wheel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mymod.jl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; trim </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> :unsafe_warn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># warns instead of erroring</span></span></code></pre></div><p>See the <a href="/ParselTongue.jl/dev/reference/api#Building">API Reference</a> for the full docstrings of <a href="/ParselTongue.jl/dev/reference/api#ParselTongue.build_extension"><code>build_extension</code></a> and <a href="/ParselTongue.jl/dev/reference/api#ParselTongue.build_wheel"><code>build_wheel</code></a>.</p>`,26)])])}const k=i(l,[["render",n]]);export{u as __pageData,k as default};
